#!/usr/bin/env python3
"""Test if preprocessor accepts list-of-dicts (transition list)."""
import os
os.environ['HF_HUB_OFFLINE'] = '1'
import torch
from lerobot.policies.pi0 import PI0Policy
from lerobot.policies.factory import make_pre_post_processors
from PIL import Image
import numpy as np

print("Loading base Pi0...")
policy = PI0Policy.from_pretrained("lerobot/pi0_base")
preprocess, postprocess = make_pre_post_processors(policy.config, "lerobot/pi0_base")

print("Creating fake transition...")
img = Image.fromarray(np.random.randint(0,255,(224,224,3), dtype=np.uint8))
transition = {
    "observation": {
        "images": {
            "base_0_rgb": img,
            "left_wrist_0_rgb": img,
            "right_wrist_0_rgb": img,
        },
        "state": torch.rand(32),
    },
    "action": torch.rand(50,32),
    "complementary_data": {"task": "pick up the cup"},
}
batch = [transition]

print("Testing preprocess with list of dicts...")
try:
    output = preprocess(batch)
    print("Success! Output type:", type(output))
    if isinstance(output, dict):
        print(" Output keys:", output.keys())
        for k,v in output.items():
            if isinstance(v, torch.Tensor):
                print(f"  {k}: shape {v.shape}")
            else:
                print(f"  {k}: {type(v)}")
except Exception as e:
    print("Error with list of dicts:", e)
    # Try single dict
    try:
        output = preprocess(transition)
        print("Single dict success:", type(output))
    except Exception as e2:
        print("Single dict error:", e2)
